-- ============================================
-- Fluxo 5B expansao parlamentar Senado
-- Seed parcial ampliado: Lote B Flavio Bolsonaro / projetos_lei
-- ============================================
-- DRAFT: nao aplicar ao Supabase remoto sem dry-run estreito e autorizacao
-- explicita do usuario neste prompt nao foi concedida (artefato fica como
-- draft local). Quando autorizado, aplicar com:
--   supabase db push --linked --dry-run
-- e em seguida:
--   supabase db push --linked
--
-- Fonte oficial: Senado Federal - Dados Abertos (Atividade Legislativa)
--   https://legis.senado.leg.br/dadosabertos/senador/5894/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}
--   Pagina publica: https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Snapshot deste lote: 2026-05-01 (versao do servico legado: 7).
-- Nota: endpoint legado /dadosabertos/senador/{codigo}/autorias.json esta em
-- descontinuacao (DataDepreciacao 2025-03-18; DataDesativacaoCompleta
-- 2026-02-01). Substituto oficial:
--   https://legis.senado.leg.br/dadosabertos/processo
-- A migracao para o novo endpoint vira como follow-up em proximo lote;
-- esta coleta ainda foi obtida com sucesso em 2026-05-01.
--
-- Artefato de auditoria:
--   fonte interna de curadoria
-- Coverage scope: inventario_parlamentar_ampliado_parcial_senado_lote_b_20260501
-- Linhas verificadas: 62
-- Filtro: IndicadorAutorPrincipal=Sim (endpoint senador/5894/autorias.json)
--   E NumOrdemAutor=1 (endpoint materia/autoria/{codigo}) E
--   CodigoParlamentar=5894 E SiglaSubtipoMateria IN
--   (PL, PEC, PLP, PDL, PCE, PRS).
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO altera nem deleta as 5 rows aplicadas no Lote A
--   (PEC 32/2019, PL 2393/2019, PL 4475/2021, PL 5593/2025, PL 1019/2026
--    com proposicao_id_api 135977, 136390, 151329, 171423, 172949).
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO inclui requerimentos (REQ, RQS, RQN, R.S), denuncias
--   (DEN) ou peticoes (PET); 111 dessas autorias principais ficam fora de
--   projetos_lei por escopo de tabela.
-- Esta migration NAO promove status para inventario_completo: ALERJ
--   (Assembleia Legislativa do RJ, mandato 1991-2018) permanece como
--   limite estrutural fora desta fonte; status publico continua
--   "ampliado_parcial".
--
-- coverage_id permanece NULL nestas rows (somente coverage_scope e
-- metadata populados); o registro em COMPLETE_PARLAMENTAR_AUTHORSHIP_COVERAGE
-- nao deve ser estendido a flavio-bolsonaro neste lote.
-- ============================================

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM candidatos c
    WHERE c.slug = 'flavio-bolsonaro'
  ) THEN
    RAISE EXCEPTION 'flavio-bolsonaro nao encontrado em candidatos';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM candidatos c
    JOIN historico_politico hp ON hp.candidato_id = c.id
    WHERE c.slug = 'flavio-bolsonaro'
      AND hp.tipo_evento = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND hp.estado = 'RJ'
      AND hp.periodo_inicio <= 2019
  ) THEN
    RAISE EXCEPTION 'mandato Senador/RJ de flavio-bolsonaro com inicio <= 2019 nao encontrado em historico_politico';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM candidatos c
    JOIN historico_politico hp ON hp.candidato_id = c.id
    WHERE c.slug = 'flavio-bolsonaro'
      AND hp.tipo_evento = 'mandato'
      AND (
        hp.cargo ILIKE '%Presidente%'
        OR hp.cargo ILIKE '%Governador%'
        OR hp.cargo ILIKE '%Prefeito%'
        OR hp.cargo_canonico IN ('Presidente', 'Governador', 'Prefeito')
      )
  ) THEN
    RAISE EXCEPTION 'flavio-bolsonaro tem mandato de chefe do Executivo no historico_politico; rota parlamentar deste lote esta incorreta';
  END IF;
END $$;

-- Pre-condicao: schema uplift 20260430070000 (coverage_id, coverage_scope,
-- metadata) ja aplicado.
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'projetos_lei' AND column_name = 'coverage_scope'
  ) THEN
    RAISE EXCEPTION 'Pre-apply: projetos_lei.coverage_scope ausente; aplique 20260430070000 primeiro';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'projetos_lei' AND column_name = 'metadata'
  ) THEN
    RAISE EXCEPTION 'Pre-apply: projetos_lei.metadata ausente; aplique 20260430070000 primeiro';
  END IF;
END $$;

-- Pre-condicao: as 5 rows do Lote A devem estar presentes intactas e nao
-- deve haver row legacy NULL pendente do cleanup 20260429235959.
DO $$
DECLARE
  cand_id uuid;
  lote_a_count int;
  legacy_null_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'flavio-bolsonaro';

  SELECT count(*) INTO lote_a_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('135977', '136390', '151329', '171423', '172949');
  IF lote_a_count <> 5 THEN
    RAISE EXCEPTION 'Pre-apply: esperadas 5 rows do Lote A intactas, encontradas %', lote_a_count;
  END IF;

  SELECT count(*) INTO legacy_null_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IS NULL;
  IF legacy_null_count <> 0 THEN
    RAISE EXCEPTION 'Pre-apply: encontradas % rows legacy com proposicao_id_api NULL; aplique cleanup 20260429235959 primeiro', legacy_null_count;
  END IF;
END $$;

