-- Idempotente: ON CONFLICT DO NOTHING. Re-rodar nao duplica nem sobrescreve.
WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'flavio-bolsonaro'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  NULL::text AS coverage_id,
  'inventario_parlamentar_ampliado_parcial_senado_lote_b_20260501'::text AS coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_flavio_bolsonaro_parlamentar_lote_b_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO NOTHING;

-- Pos-apply: 62 rows do Lote B presentes; 5 do Lote A intactas; total Senado
-- = 67; coverage_id continua NULL para todas as rows do Flavio (status
-- ampliado_parcial, sem registro em COMPLETE_PARLAMENTAR_AUTHORSHIP_COVERAGE);
-- nenhum outro slug afetado.
DO $$
DECLARE
  cand_id uuid;
  lote_b_count int;
  lote_a_count int;
  total_senado int;
  with_target_scope int;
  null_coverage_id int;
  any_coverage_id_set int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'flavio-bolsonaro';

  SELECT count(*) INTO lote_b_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN (
    '136894', '135687', '135938', '136027', '136253', '136254', '136251', '136252',
    '136262', '136371', '136918', '136970', '136978', '137241', '137330', '138227',
    '140268', '136764', '138702', '141305', '142510', '148048', '149150', '148902',
    '148903', '149286', '151330', '150245', '151868', '152626', '152627', '152628',
    '152773', '155771', '156769', '158826', '157069', '158333', '160817', '161629',
    '161721', '155978', '166887', '162279', '165920', '167042', '167313', '172022',
    '167238', '168298', '169490', '169779', '169904', '170061', '170485', '170486',
    '170769', '170925', '171424', '171453', '172830', '173320'
    );
  IF lote_b_count <> 62 THEN
    RAISE EXCEPTION 'Pos-apply: esperadas 62 rows do Lote B em projetos_lei (Senado), encontradas %', lote_b_count;
  END IF;

  SELECT count(*) INTO lote_a_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('135977', '136390', '151329', '171423', '172949');
  IF lote_a_count <> 5 THEN
    RAISE EXCEPTION 'Pos-apply: Lote A perdeu rows; esperado 5, encontrado %', lote_a_count;
  END IF;

  SELECT count(*) INTO total_senado
  FROM projetos_lei
  WHERE candidato_id = cand_id AND fonte = 'Senado';
  IF total_senado <> 67 THEN
    RAISE EXCEPTION 'Pos-apply: total Senado esperado 67 (5 Lote A + 62 Lote B), encontrado %', total_senado;
  END IF;

  SELECT count(*) INTO with_target_scope
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND coverage_scope = 'inventario_parlamentar_ampliado_parcial_senado_lote_b_20260501';
  IF with_target_scope <> 62 THEN
    RAISE EXCEPTION 'Pos-apply: esperadas 62 rows com coverage_scope alvo, encontradas %', with_target_scope;
  END IF;

  SELECT count(*) INTO any_coverage_id_set
  FROM projetos_lei
  WHERE candidato_id = cand_id AND coverage_id IS NOT NULL;
  IF any_coverage_id_set <> 0 THEN
    RAISE EXCEPTION 'Pos-apply: encontradas % rows do flavio-bolsonaro com coverage_id NAO NULL; status ampliado_parcial requer coverage_id NULL', any_coverage_id_set;
  END IF;

  RAISE NOTICE 'Pos-apply flavio-bolsonaro Lote B: lote_b=% lote_a=% total_senado=% scope_alvo=% coverage_id_nao_nulo=%',
    lote_b_count, lote_a_count, total_senado, with_target_scope, any_coverage_id_set;
END $$;
